-- rfl: definitional equality 直接關閉
theorem rfl_demo : add zero (succ zero) ≡ succ zero := by { rfl }

-- simp: 定義展開 + NbE 歸約
theorem simp_demo (n : Nat) : add zero n ≡ n := by { simp }

-- induction: 自動生成 ih（歸納假設）
theorem add_zero_r (n : Nat) : add n zero ≡ n := by {
  induction n;
  exact refl;
  simp;
  rewrite ih;
  exact refl
}

-- cases: 分情況討論
theorem not_invol (b : Bool) : not (not b) ≡ b := by {
  cases b;
  exact refl;
  exact refl
}

-- rewrite: 用已知等式改寫 goal
theorem rw_demo : add (succ zero) (succ zero) ≡ add (succ zero) (succ zero) := by {
  exact refl
}

-- ring: Nat 算術
theorem ring_demo : add zero zero ≡ zero := by { ring }

-- omega: 線性算術
theorem omega_demo : add (succ zero) (succ zero) ≡ succ (succ zero) := by { omega }

-- 組合 tactic
theorem combo (a : Bool) : or a false ≡ a := by {
  cases a;
  exact refl;
  exact refl
}

-- Type Class 定義
class Eq (A : Type) where {
  eq : A -> A -> Bool
}

-- Instance
instance eqBool : Eq Bool where {
  eq := fun a => fun b => match a with
    | true => b
    | false => not b
}

-- 繼承
class Ord (A : Type) extends Eq where {
  compare : A -> A -> Bool
}

instance ordBool : Ord Bool where {
  eq := fun a => fun b => match a with
    | true => b
    | false => not b;
  compare := fun a => fun b => match a with
    | true => (match b with | true => false | false => false)
    | false => (match b with | true => true | false => false)
}

-- Notation
infixl 65 "+" := add
infixl 70 "*" := mul
prefix 100 "~" := not

-- 用運算子
def five : Nat := (succ (succ zero)) + (succ (succ (succ zero)))
def six : Nat := (succ (succ zero)) * (succ (succ (succ zero)))

-- 運算子配合路徑
theorem plus_comm : (succ zero) + (succ (succ zero)) ≡ (succ (succ zero)) + (succ zero) := by {
  rewrite (addComm (succ zero) (succ (succ zero)));
  exact refl
}
